impl Default for TurnConfig {
    fn default() -> Self {
        Self {
            confidence_threshold: 0.60,
            token_budget: 60_000,
            max_output_tokens: 4096,
            model: "claude-sonnet-4-5".into(),
            parallel_cap: 8,
            cancel: None,
        }
    }
}

